template<class F> ll mgr(ll ok, ll ng, F f) {

    if (ok < ng)

        while (ng - ok > 1) {

            ll mid = (ok + ng) / 2;

            if (f(mid))ok = mid; else ng = mid;

        }

    else

        while (ok - ng > 1) {

            ll mid = (ok + ng) / 2;

            if (f(mid))ok = mid; else ng = mid;

        }

    return ok;

}

